            modelBuilder.Entity("SmartRecruit.Domain.Entities.Applications", b =>
                {
                    b.HasOne("SmartRecruit.Domain.Entities.User", "Candidate")
                        .WithMany("Applications")
                        .HasForeignKey("CandidateId")
                        .OnDelete(DeleteBehavior.Restrict)
                        .IsRequired();

                    b.HasOne("SmartRecruit.Domain.Entities.Job", "Job")
                        .WithMany("Applications")
                        .HasForeignKey("JobId")
                        .OnDelete(DeleteBehavior.Cascade)
                        .IsRequired();

                    b.Navigation("Candidate");

                    b.Navigation("Job");
                });

            modelBuilder.Entity("SmartRecruit.Domain.Entities.CandidateProfile", b =>
                {
                    b.HasOne("SmartRecruit.Domain.Entities.User", "User")
                        .WithOne("CandidateProfile")
                        .HasForeignKey("SmartRecruit.Domain.Entities.CandidateProfile", "UserId")
